# Task: Integration Test for Rapid File Changes

## Location
Create: `tests/e2e/background_worker_test.go`

## Purpose

This is the ultimate validation that our background worker architecture works: simulate the multi-agent scenario and verify the UI remains responsive.

## Test Scenario

```
1. Start TUI with background worker
2. Spawn goroutine that writes to beads.jsonl every 50ms
3. Simultaneously send keyboard events to UI
4. Measure latency between keypress and response
5. Assert latency < 50ms (aspirational target)
```

## Implementation

```go
package e2e

import (
    "testing"
    "time"
    "os"
    "sync"
    "sync/atomic"

    tea "github.com/charmbracelet/bubbletea"
    "github.com/stretchr/testify/require"
)

func TestUIResponsiveDuringRapidWrites(t *testing.T) {
    // Skip in short mode
    if testing.Short() {
        t.Skip("skipping integration test in short mode")
    }

    // Create temp beads file
    tmpDir := t.TempDir()
    beadsFile := filepath.Join(tmpDir, ".beads", "beads.jsonl")
    require.NoError(t, os.MkdirAll(filepath.Dir(beadsFile), 0755))
    writeInitialBeads(t, beadsFile, 100) // Start with 100 issues

    // Create model with background worker
    model, err := ui.NewModel(
        ui.WithBeadsPath(beadsFile),
        ui.WithBackgroundWorker(true),
    )
    require.NoError(t, err)

    // Create test program
    var (
        latencies    []time.Duration
        latencyMu    sync.Mutex
        writeCount   atomic.Int64
        running      atomic.Bool
    )
    running.Store(true)

    // Start writer goroutine (simulates agents)
    go func() {
        ticker := time.NewTicker(50 * time.Millisecond)
        defer ticker.Stop()

        for running.Load() {
            select {
            case <-ticker.C:
                appendIssue(beadsFile, writeCount.Add(1))
            }
        }
    }()

    // Create custom program that measures latency
    var lastKeyTime time.Time
    measureLatency := func(m tea.Model, msg tea.Msg) (tea.Model, tea.Cmd) {
        switch msg.(type) {
        case tea.KeyMsg:
            lastKeyTime = time.Now()
        }

        newModel, cmd := m.Update(msg)

        // Measure time from keypress to update completion
        if !lastKeyTime.IsZero() {
            latency := time.Since(lastKeyTime)
            latencyMu.Lock()
            latencies = append(latencies, latency)
            latencyMu.Unlock()
            lastKeyTime = time.Time{}
        }

        return newModel, cmd
    }

    // Run test for 5 seconds
    testDuration := 5 * time.Second
    keyInterval := 100 * time.Millisecond

    done := make(chan struct{})
    go func() {
        // Simulate user input
        ticker := time.NewTicker(keyInterval)
        defer ticker.Stop()

        endTime := time.Now().Add(testDuration)
        for time.Now().Before(endTime) {
            <-ticker.C
            // Send navigation key
            model, _ = measureLatency(model, tea.KeyMsg{Type: tea.KeyDown})
        }
        close(done)
    }()

    <-done
    running.Store(false)

    // Analyze results
    latencyMu.Lock()
    defer latencyMu.Unlock()

    require.NotEmpty(t, latencies, "should have measured some latencies")

    // Calculate statistics
    var total time.Duration
    var max time.Duration
    var over50ms int

    for _, l := range latencies {
        total += l
        if l > max {
            max = l
        }
        if l > 50*time.Millisecond {
            over50ms++
        }
    }

    avg := total / time.Duration(len(latencies))

    t.Logf("Latency stats: avg=%v, max=%v, over50ms=%d/%d (%.1f%%)",
        avg, max, over50ms, len(latencies),
        float64(over50ms)/float64(len(latencies))*100)
    t.Logf("Write count: %d", writeCount.Load())

    // Assert requirements
    require.Less(t, avg, 50*time.Millisecond, "average latency should be < 50ms")
    require.Less(t, float64(over50ms)/float64(len(latencies)), 0.05,
        "less than 5% of events should exceed 50ms")
}

func TestNoDataRacesDuringRapidUpdates(t *testing.T) {
    // This test relies on -race flag to detect races
    // Run with: go test -race ./tests/e2e/...

    tmpDir := t.TempDir()
    beadsFile := filepath.Join(tmpDir, ".beads", "beads.jsonl")
    require.NoError(t, os.MkdirAll(filepath.Dir(beadsFile), 0755))
    writeInitialBeads(t, beadsFile, 50)

    model, err := ui.NewModel(ui.WithBeadsPath(beadsFile))
    require.NoError(t, err)

    var wg sync.WaitGroup
    done := make(chan struct{})

    // Writer
    wg.Add(1)
    go func() {
        defer wg.Done()
        for i := 0; i < 100; i++ {
            select {
            case <-done:
                return
            default:
                appendIssue(beadsFile, int64(i))
                time.Sleep(10 * time.Millisecond)
            }
        }
    }()

    // Reader (UI)
    wg.Add(1)
    go func() {
        defer wg.Done()
        for i := 0; i < 100; i++ {
            select {
            case <-done:
                return
            default:
                _ = model.View() // Should not race with writes
                model, _ = model.Update(tea.KeyMsg{Type: tea.KeyDown})
                time.Sleep(10 * time.Millisecond)
            }
        }
    }()

    wg.Wait()
    close(done)
}

// Helper functions

func writeInitialBeads(t *testing.T, path string, count int) {
    f, err := os.Create(path)
    require.NoError(t, err)
    defer f.Close()

    for i := 0; i < count; i++ {
        issue := fmt.Sprintf(`{"id":"issue-%d","title":"Issue %d","status":"open"}`, i, i)
        fmt.Fprintln(f, issue)
    }
}

func appendIssue(path string, n int64) {
    f, err := os.OpenFile(path, os.O_APPEND|os.O_WRONLY, 0644)
    if err != nil {
        return // Ignore errors in test helper
    }
    defer f.Close()

    issue := fmt.Sprintf(`{"id":"new-%d","title":"New Issue %d","status":"open"}`, n, n)
    fmt.Fprintln(f, issue)
}
```

## What This Tests

1. **Responsiveness**: UI update latency under load
2. **Data Races**: Race detector finds concurrency bugs
3. **Coalescing**: Verifies rapid writes don't cause queue buildup
4. **Memory Stability**: (Extended test) Heap doesn't grow unbounded

