# Task: Implement buildSnapshot() Core Loading Logic

## Location
Add to: `pkg/ui/background_worker.go`

## Purpose

This is the heart of the background processing - the method that does all the expensive work OFF the UI thread. When this method runs, the UI remains fully responsive.

## Implementation

```go
// buildSnapshot creates a complete DataSnapshot from the beads file.
//
// This method is called from the worker goroutine, NOT the UI thread.
// It can take 100-500ms+ for large files, which is fine because
// the UI continues to operate with the previous snapshot.
//
// Returns nil, nil if content unchanged (dedup optimization).
// Returns nil, err if loading failed.
func (w *BackgroundWorker) buildSnapshot() (*DataSnapshot, error) {
    start := time.Now()

    // === Step 1: Load raw issues from file ===
    // This is I/O bound - disk read + JSON parsing
    // Can take 50-200ms for large files

    issues, err := loader.LoadIssuesFromFileWithOptions(
        w.beadsPath,
        loader.LoadOptions{
            MaxLineSize:    10 * 1024 * 1024, // 10MB max line
            SkipMalformed:  true,              // Continue on parse errors
            ValidateSchema: true,              // Check required fields
        },
    )
    if err != nil {
        return nil, fmt.Errorf("loading issues from %s: %w", w.beadsPath, err)
    }

    loadDuration := time.Since(start)

    // === Step 2: Compute content hash for dedup ===
    // If the file was touched but content is identical, skip processing

    hash := w.computeContentHash(issues)
    if hash == w.lastHash {
        // Content unchanged - no need to rebuild
        log.Printf("buildSnapshot: content unchanged, skipping rebuild")
        return nil, nil
    }
    w.lastHash = hash

    // === Step 3: Build lookup structures ===

    issueMap := make(map[string]*model.Issue, len(issues))
    for i := range issues {
        issue := &issues[i]
        issueMap[issue.ID] = issue
    }

    // === Step 4: Compute statistics ===
    // Pre-compute counts so UI doesn't have to iterate

    var (
        openCount    int
        closedCount  int
        blockedCount int
        readyCount   int
        inProgressCount int
    )

    for _, issue := range issues {
        switch issue.Status {
        case model.StatusOpen:
            openCount++
            if !w.hasOpenBlockers(&issue, issueMap) {
                readyCount++
            }
        case model.StatusClosed:
            closedCount++
        case model.StatusBlocked:
            blockedCount++
        case model.StatusInProgress:
            inProgressCount++
        }
    }

    // === Step 5: Run Phase 1 analysis ===
    // This builds the graph and computes basic metrics
    // Takes 20-100ms depending on graph size

    analyzeStart := time.Now()
    analyzer := analysis.NewAnalyzer(issues)
    stats := analyzer.AnalyzePhase1() // Only Phase 1, synchronous
    analyzeDuration := time.Since(analyzeStart)

    // === Step 6: Create snapshot ===

    version := w.nextVersion.Add(1)
    snapshot := &DataSnapshot{
        // Core data
        Issues:   issues,
        IssueMap: issueMap,

        // Analysis (Phase 1 complete, Phase 2 pending)
        Stats:       stats,
        Phase2Ready: false,

        // Metadata
        Version:     version,
        ContentHash: hash,
        LoadedAt:    time.Now(),
        SourcePath:  w.beadsPath,

        // Statistics
        TotalCount:      len(issues),
        OpenCount:       openCount,
        ClosedCount:     closedCount,
        BlockedCount:    blockedCount,
        ReadyCount:      readyCount,
        InProgressCount: inProgressCount,

        // View data (populated by Phase 3 tasks)
        ListItems:    nil,
        BoardState:   nil,
        TreeNodes:    nil,
        GraphLayout:  nil,
        InsightsData: nil,
    }

    // === Step 7: Kick off Phase 2 analysis (async) ===
    // This runs PageRank, Betweenness, etc. in yet another goroutine
    // UI will be notified via Phase2UpdateMsg when complete

    go w.runPhase2Analysis(stats, version)

    totalDuration := time.Since(start)
    log.Printf("buildSnapshot: loaded %d issues (load=%v, analyze=%v, total=%v)",
        len(issues), loadDuration, analyzeDuration, totalDuration)

    return snapshot, nil
}

// computeContentHash creates a deterministic hash of issue content.
// Used to detect when file was touched but content is unchanged.
//
// Only hashes stable fields - excludes timestamps that change on touch.
func (w *BackgroundWorker) computeContentHash(issues []model.Issue) string {
    h := sha256.New()

    // Sort by ID for deterministic ordering
    // (JSONL order might change during compaction)
    sorted := make([]model.Issue, len(issues))
    copy(sorted, issues)
    sort.Slice(sorted, func(i, j int) bool {
        return sorted[i].ID < sorted[j].ID
    })

    for _, issue := range sorted {
        // Hash identifying and content fields only
        fmt.Fprintf(h, "%s|%s|%s|%d|%s|%d|",
            issue.ID,
            issue.Title,
            issue.Status,
            issue.Priority,
            issue.Description,
            len(issue.Dependencies),
        )
        // Include dependency IDs (not timestamps)
        for _, dep := range issue.Dependencies {
            fmt.Fprintf(h, "dep:%s|", dep.ID)
        }
    }

    return hex.EncodeToString(h.Sum(nil))
}

// hasOpenBlockers checks if an issue is blocked by any open issue.
func (w *BackgroundWorker) hasOpenBlockers(issue *model.Issue, issueMap map[string]*model.Issue) bool {
    for _, dep := range issue.Dependencies {
        if dep.Type.IsBlocking() {
            if blocker, exists := issueMap[dep.ID]; exists {
                switch blocker.Status {
                case model.StatusOpen, model.StatusBlocked, model.StatusInProgress:
                    return true
                }
            }
        }
    }
    return false
}
```

## Error Handling Strategy

```go
// Errors are logged but don't crash the worker.
// The worker continues watching for the next change.

if err != nil {
    // Send error to UI for display
    select {
    case w.errorCh <- SnapshotErrorMsg{
        Err:         err,
        Recoverable: isRecoverableError(err),
    }:
    default:
    }
    return nil, err
}

func isRecoverableError(err error) bool {
    // File not found, permission denied = might recover
    // Parse error in specific issue = recoverable
    // Out of memory = not recoverable
    return !errors.Is(err, ErrFatal)
}
```

