func (m Model) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
    switch msg := msg.(type) {

    case SnapshotReadyMsg:
        // THIS IS THE CRITICAL PATH - must be fast!
        // All we do is swap a pointer. O(1), sub-microsecond.

        old := m.snapshot
        m.snapshot = msg.Snapshot

        // Preserve selection if possible
        if old != nil && m.snapshot != nil {
            m.reconcileSelection(old, m.snapshot)
        }

        // Re-register to listen for next snapshot
        return m, tea.Batch(
            m.waitForSnapshot(),
            m.waitForPhase2(),
            m.waitForError(),
        )

    case Phase2UpdateMsg:
        // Phase 2 metrics are now available
        // Just trigger a re-render; data is already in snapshot.Stats
        if m.snapshot != nil && msg.Version == m.snapshot.Version {
            m.snapshot.Phase2Ready = true
        }
        return m, m.waitForPhase2()

    case SnapshotErrorMsg:
        // Display error but keep using old snapshot
        m.lastError = msg.Err
        m.showError = true
        return m, m.waitForError()

    // ... existing message handlers ...
    }
}

// reconcileSelection tries to preserve the user's selection after snapshot swap.
func (m *Model) reconcileSelection(old, new *DataSnapshot) {
    if m.selectedID == "" {
        return
    }

    // Try to find the same issue in the new snapshot
    if _, exists := new.IssueMap[m.selectedID]; exists {
        // Issue still exists, find its index in the list
        for i, item := range new.ListItems {
            if listItem, ok := item.(IssueListItem); ok && listItem.ID == m.selectedID {
                m.list.Select(i)
                return
            }
        }
    }

    // Issue no longer exists or moved - clear selection
    // or select nearest item
    m.selectedID = ""
}
