func (m Model) listenForSnapshots() tea.Cmd {
    return func() tea.Msg {
        select {
        case msg := <-m.snapshotCh:
            return msg
        case msg := <-m.phase2Ch:
            return msg
        case msg := <-m.errorCh:
            return msg
        }
