### Modified Search Function (viewer.js)

```javascript
async function searchIssues(term, options = {}) {
    const { mode = 'text', preset = 'default', limit = 50 } = options;

    // Get FTS results with metrics
    const sql = `
        SELECT i.id, i.title, i.status, i.priority, 
               i.pagerank, i.blocker_count, i.updated_at,
               snippet(issues_fts, 2, '<mark>', '</mark>', '...', 32) as snippet,
               bm25(issues_fts) as bm25_score
        FROM issues_fts
        JOIN issue_overview_mv i ON issues_fts.id = i.id
        WHERE issues_fts MATCH ?
        ORDER BY bm25(issues_fts)
        LIMIT ?
    `;
    const results = execQuery(sql, [term + '*', limit * 2]); // Over-fetch for re-ranking

    if (mode === 'hybrid') {
        const scorer = new HybridScorer(PRESETS[preset]);
        // Normalize BM25 scores to 0-1 range
        const maxBM25 = Math.max(...results.map(r => Math.abs(r.bm25_score)));
        const normalized = results.map(r => ({
            ...r,
            textScore: maxBM25 > 0 ? (1 - r.bm25_score / maxBM25) : 0.5
        }));

        const ranked = scorer.scoreAndRank(normalized);
        return ranked.slice(0, limit);
    }

    return results.slice(0, limit);
}
```

