# Task: Pre-compute BoardState in Background

## Location
Add to: `pkg/ui/background_worker.go` or `pkg/ui/snapshot_builders.go`

## Purpose

The Kanban board groups issues by status into columns. Currently, this grouping happens on every render. By pre-computing in background, board rendering becomes instant.

## Implementation

```go
// BoardSnapshot contains pre-computed Kanban board layout
type BoardSnapshot struct {
    Columns []BoardColumn

    // Quick access by status
    ColumnByStatus map[model.Status]int  // status -> column index

    // Total counts for header
    TotalCards int
}

type BoardColumn struct {
    Status      model.Status
    Title       string          // "Open", "In Progress", etc.
    HeaderStyle lipgloss.Style  // Pre-computed style

    Cards []BoardCard

    // Pre-computed stats
    CardCount    int
    HighPriCount int  // P0 + P1
    BlockedCount int
}

type BoardCard struct {
    Issue *model.Issue

    // Pre-computed display elements
    BorderStyle  lipgloss.Style  // Based on blocked/blocking/ready state
    TypeIcon     string
    PriorityBadge string
    AgeDisplay   string
    AssigneeBadge string

    // Pre-computed dependency info
    BlockedByIDs []string
    BlocksIDs    []string
    LabelNames   []string
}

func (w *BackgroundWorker) buildBoardState(
    issues []model.Issue,
    issueMap map[string]*model.Issue,
) *BoardSnapshot {
    // Initialize columns in display order
    columns := []BoardColumn{
        {Status: model.StatusOpen, Title: "Open", Cards: make([]BoardCard, 0)},
        {Status: model.StatusInProgress, Title: "In Progress", Cards: make([]BoardCard, 0)},
        {Status: model.StatusBlocked, Title: "Blocked", Cards: make([]BoardCard, 0)},
        {Status: model.StatusClosed, Title: "Closed", Cards: make([]BoardCard, 0)},
    }

    columnByStatus := make(map[model.Status]int)
    for i, col := range columns {
        columnByStatus[col.Status] = i
    }

    // Distribute issues to columns
    for _, issue := range issues {
        colIdx, exists := columnByStatus[issue.Status]
        if !exists {
            colIdx = 0 // Default to Open
        }

        card := w.buildBoardCard(&issue, issueMap)
        columns[colIdx].Cards = append(columns[colIdx].Cards, card)
        columns[colIdx].CardCount++

        if issue.Priority <= 1 {
            columns[colIdx].HighPriCount++
        }
        if len(card.BlockedByIDs) > 0 {
            columns[colIdx].BlockedCount++
        }
    }

    // Sort cards within each column (priority, then created)
    for i := range columns {
        sortBoardCards(columns[i].Cards)
    }

    // Compute header styles
    for i := range columns {
        columns[i].HeaderStyle = w.computeColumnHeaderStyle(columns[i])
    }

    return &BoardSnapshot{
        Columns:        columns,
        ColumnByStatus: columnByStatus,
        TotalCards:     len(issues),
    }
}

func (w *BackgroundWorker) buildBoardCard(
    issue *model.Issue,
    issueMap map[string]*model.Issue,
) BoardCard {
    // Collect blocked-by IDs
    blockedByIDs := make([]string, 0)
    blocksIDs := make([]string, 0)

    for _, dep := range issue.Dependencies {
        if dep.Type.IsBlocking() {
            if blocker, exists := issueMap[dep.ID]; exists {
                if blocker.Status != model.StatusClosed {
                    blockedByIDs = append(blockedByIDs, dep.ID)
                }
            }
        }
    }

    // Find issues this blocks
    for _, other := range issueMap {
        for _, dep := range other.Dependencies {
            if dep.ID == issue.ID && dep.Type.IsBlocking() {
                blocksIDs = append(blocksIDs, other.ID)
            }
        }
    }

    // Determine border style based on state
    borderStyle := w.computeCardBorderStyle(issue, blockedByIDs, blocksIDs)

    return BoardCard{
        Issue:         issue,
        BorderStyle:   borderStyle,
        TypeIcon:      renderTypeIcon(issue.IssueType),
        PriorityBadge: renderPriorityBadge(issue.Priority),
        AgeDisplay:    formatAge(issue.CreatedAt),
        AssigneeBadge: renderAssignee(issue.Assignee),
        BlockedByIDs:  blockedByIDs,
        BlocksIDs:     blocksIDs,
        LabelNames:    issue.Labels,
    }
}

func (w *BackgroundWorker) computeCardBorderStyle(
    issue *model.Issue,
    blockedByIDs, blocksIDs []string,
) lipgloss.Style {
    baseStyle := lipgloss.NewStyle().Padding(0, 1)

    // Red border: blocked by others
    if len(blockedByIDs) > 0 {
        return baseStyle.BorderForeground(lipgloss.Color("#ff6b6b"))
    }

    // Yellow border: blocks others (high impact)
    if len(blocksIDs) > 0 {
        return baseStyle.BorderForeground(lipgloss.Color("#ffd93d"))
    }

    // Green border: ready to work (open with no blockers)
    if issue.Status == model.StatusOpen {
        return baseStyle.BorderForeground(lipgloss.Color("#6bcb77"))
    }

    // Default border
    return baseStyle.BorderForeground(lipgloss.Color("#666666"))
}
```

