# Task: Pre-compute ListItems in Background

## Location
Add to: `pkg/ui/background_worker.go` or `pkg/ui/snapshot_builders.go`

## Purpose

The list view is the most common view. Currently, it builds list.Item slice on every render, applying filters and sorts. This takes 30-50ms for large datasets.

By pre-computing ListItems in the background, rendering becomes O(visible items).

## Current Problem

```go
// In model.go View() or helpers
func (m Model) buildListItems() []list.Item {
    var items []list.Item
    for _, issue := range m.issues {
        if m.matchesFilter(issue) {    // O(1) per issue
            items = append(items, issueItem{issue})  // allocation
        }
    }
    m.applySort(items)  // O(n log n)
    return items
}
// Total: O(n log n) - 30-50ms for 1000 issues
```

## Solution

Pre-compute in background:

```go
// In background_worker.go
func (w *BackgroundWorker) buildListItems(
    issues []model.Issue,
    issueMap map[string]*model.Issue,
    recipe *recipe.Recipe,
) []list.Item {
    // 1. Apply filters
    filtered := make([]model.Issue, 0, len(issues))
    for _, issue := range issues {
        if recipe.Matches(issue) {
            filtered = append(filtered, issue)
        }
    }

    // 2. Apply sort
    recipe.Sort(filtered)

    // 3. Build list items
    items := make([]list.Item, len(filtered))
    for i, issue := range filtered {
        items[i] = newIssueListItem(issue, issueMap)
    }

    return items
}

// newIssueListItem creates a list.Item with pre-computed display strings
func newIssueListItem(issue model.Issue, issueMap map[string]*model.Issue) list.Item {
    return IssueListItem{
        ID:           issue.ID,
        Title:        issue.Title,
        Status:       issue.Status,
        Priority:     issue.Priority,

        // Pre-compute display strings
        StatusBadge:  renderStatusBadge(issue.Status),
        PriorityBadge: renderPriorityBadge(issue.Priority),
        TypeIcon:     renderTypeIcon(issue.IssueType),

        // Pre-compute blocking info
        BlockedByCount: countOpenBlockers(issue, issueMap),
        BlocksCount:    countBlockedBy(issue, issueMap),

        // Pre-compute age display
        AgeDisplay:    formatAge(issue.CreatedAt),

        // Store reference for detail view
        Issue: &issue,
    }
}

// IssueListItem implements list.Item with pre-computed display data
type IssueListItem struct {
    ID             string
    Title          string
    Status         model.Status
    Priority       int

    // Pre-computed display strings (avoid formatting on render)
    StatusBadge    string
    PriorityBadge  string
    TypeIcon       string
    AgeDisplay     string

    // Pre-computed counts
    BlockedByCount int
    BlocksCount    int

    // Reference to full issue
    Issue *model.Issue
}

func (i IssueListItem) FilterValue() string {
    return i.ID + " " + i.Title
}

func (i IssueListItem) Title() string {
    return i.Title
}

func (i IssueListItem) Description() string {
    return fmt.Sprintf("%s %s %s", i.StatusBadge, i.PriorityBadge, i.ID)
}
```

## Recipe Integration

The recipe determines filters and sort order:

```go
// recipe/types.go
type Recipe struct {
    Name    string
    Filters FilterConfig
    Sort    SortConfig
}

func (r *Recipe) Matches(issue model.Issue) bool {
    // Check status filter
    if len(r.Filters.Status) > 0 {
        if !contains(r.Filters.Status, issue.Status) {
            return false
        }
    }

    // Check priority filter
    if len(r.Filters.Priority) > 0 {
        if !contains(r.Filters.Priority, issue.Priority) {
            return false
        }
    }

    // Check actionable filter
    if r.Filters.Actionable {
        // Would need issueMap - might need to pass it
    }

    // ... other filters ...

    return true
}

func (r *Recipe) Sort(issues []model.Issue) {
    sort.Slice(issues, func(i, j int) bool {
        // Sort by primary field
        cmp := r.compareField(issues[i], issues[j], r.Sort.Field)
        if cmp != 0 {
            if r.Sort.Descending {
                return cmp > 0
            }
            return cmp < 0
        }

        // Secondary sort by ID for stability
        return issues[i].ID < issues[j].ID
    })
}
```

