# AGENTS.md File Append Logic

## Background
When user accepts the prompt, safely append our blurb to their AGENTS.md file.

## Append Strategy

### Formatting
- Add two blank lines before our content
- Our content starts with marker comment
- Our content ends with end marker
- Preserve existing file content exactly

\`\`\`go
func appendBlurbToFile(filePath string, blurb string) error {
    // Read existing content
    existing, err := os.ReadFile(filePath)
    if err != nil {
        return fmt.Errorf("read file: %w", err)
    }

    // Prepare new content
    separator := "\n\n"
    if len(existing) > 0 && !bytes.HasSuffix(existing, []byte("\n")) {
        separator = "\n\n\n"  // Add extra newline if file doesn't end with one
    }

    newContent := append(existing, []byte(separator+blurb)...)

    // Write atomically
    return atomicWrite(filePath, newContent)
}
\`\`\`

### Atomic Write
\`\`\`go
func atomicWrite(filePath string, content []byte) error {
    // Write to temp file in same directory
    dir := filepath.Dir(filePath)
    tmp, err := os.CreateTemp(dir, ".bv-append-*")
    if err != nil {
        return err
    }
    tmpPath := tmp.Name()

    // Cleanup on error
    defer func() {
        if tmpPath != "" {
            os.Remove(tmpPath)
        }
    }()

    // Write content
    if _, err := tmp.Write(content); err != nil {
        return err
    }
    if err := tmp.Close(); err != nil {
        return err
    }

    // Preserve permissions
    info, err := os.Stat(filePath)
    if err == nil {
        os.Chmod(tmpPath, info.Mode())
    }

    // Atomic rename
    if err := os.Rename(tmpPath, filePath); err != nil {
        return err
    }

    tmpPath = "" // Don't cleanup - rename succeeded
    return nil
}
\`\`\`

## Error Handling
- File not writable вҶ’ show error message, don't crash
