    return m, cmd

case showTutorialMsg:
    if msg.contextOnly {
        m.tutorialModel.SetContextMode(true, msg.context)
    } else {
        m.tutorialModel.SetContextMode(false, "")
    }
    m.showTutorial = true
\`\`\`

