\`\`\`go
func (m Model) currentContext() string {
    // Check overlays first (most specific)
    if m.showLabelPicker {
        return "label-picker"
    }
    if m.showRecipePicker {
        return "recipe-picker"
    }

    // Check views
    if m.showInsightsPanel {
        return "insights"
    }
    if m.showGraph {
        return "graph"
    }
    if m.showBoard {
        return "board"
    }
    if m.showHistory {
        return "history"
    }
    if m.timeTravelMode {
        return "time-travel"
    }

    // Check detail states
    if m.isSplitView {
        return "split"
    }
    if m.showDetails {
        return "detail"
    }

    // Check filter state
    if m.list.FilterState() != list.Unfiltered {
        return "filter"
    }

    return "list"
}
