### Live Recalculation API
```javascript
function recalculateMetrics(filteredIds) {
    if (!WASM_READY) return null;

    const indices = filteredIds
        .map(id => NODE_MAP.get(id))
        .filter(idx => idx !== undefined);

    if (indices.length === 0) return null;

    const subgraph = GRAPH.subgraph(new Uint32Array(indices));

    return {
        pagerank: subgraph.pagerank(0.85, 100),
        betweenness: subgraph.betweenness(),
        cycles: JSON.parse(subgraph.detect_cycles()),
        criticalPath: subgraph.critical_path_heights(),
        density: subgraph.density(),
    };
}

function whatIfClose(issueId) {
    if (!WASM_READY) return null;

    const idx = NODE_MAP.get(issueId);
    if (idx === undefined) return null;

    const closedSet = buildClosedSet();
    return JSON.parse(GRAPH.what_if_close(idx, closedSet));
}

function buildClosedSet() {
    const n = GRAPH.node_count();
    const closed = new Uint8Array(n);

    const closedIssues = DB.exec('SELECT id FROM issues WHERE status = "closed"');
    for (const [id] of closedIssues[0]?.values || []) {
        const idx = NODE_MAP.get(id);
        if (idx !== undefined) closed[idx] = 1;
    }

    return closed;
}
```

