// countTransitiveUnblocks recursive traversal
// TopWhatIfDeltas ranking
```

## Rust Implementation (whatif.rs)
```rust
use crate::graph::DiGraph;
use wasm_bindgen::prelude::*;
use serde::Serialize;

#[derive(Serialize)]
pub struct WhatIfResult {
    /// Issues directly unblocked (immediate dependents with all blockers satisfied)
    pub direct_unblocks: usize,
    /// Total issues transitively unblocked (cascade)
    pub transitive_unblocks: usize,
    /// IDs of directly unblocked issues
    pub unblocked_ids: Vec<usize>,
    /// Parallelization gain (direct_unblocks - 1)
    pub parallel_gain: i32,
}

/// Compute what happens if a node is "closed" (removed from blocking consideration).
pub fn what_if_close(graph: &DiGraph, node: usize, closed_set: &[bool]) -> WhatIfResult {
    let n = graph.node_count();

    // Create new closed set with this node added
    let mut new_closed = closed_set.to_vec();
    if node < n {
        new_closed[node] = true;
    }

    // Find issues that become actionable (all blockers closed)
    let mut direct_unblocks = Vec::new();

    for v in 0..n {
        if new_closed[v] { continue; }

        // Check if v was blocked before but unblocked now
        let was_blocked = graph.predecessors(v).iter().any(|&p| !closed_set[p]);
        let now_unblocked = graph.predecessors(v).iter().all(|&p| new_closed[p]);

        if was_blocked && now_unblocked {
            direct_unblocks.push(v);
        }
    }

    // Count transitive unblocks (cascade effect)
    let transitive = count_cascade(graph, &direct_unblocks, &new_closed);

    WhatIfResult {
        direct_unblocks: direct_unblocks.len(),
        transitive_unblocks: transitive,
        unblocked_ids: direct_unblocks,
        parallel_gain: direct_unblocks.len() as i32 - 1,
    }
}

fn count_cascade(graph: &DiGraph, roots: &[usize], closed: &[bool]) -> usize {
    let n = graph.node_count();
    let mut visited = vec![false; n];
    let mut count = 0;
    let mut queue: Vec<usize> = roots.to_vec();

    while let Some(v) = queue.pop() {
        if visited[v] { continue; }
        visited[v] = true;
        count += 1;

        // Add successors that become actionable
        for &w in graph.successors(v) {
            if visited[w] || closed[w] { continue; }
            // Check if all predecessors of w are now "resolved"
            let all_resolved = graph.predecessors(w).iter()
                .all(|&p| closed[p] || visited[p]);
            if all_resolved {
                queue.push(w);
            }
        }
    }

    count
}

/// Find top N issues with highest cascade impact.
pub fn top_what_if(graph: &DiGraph, closed_set: &[bool], n: usize) -> Vec<(usize, WhatIfResult)> {
    let node_count = graph.node_count();
    let mut results: Vec<(usize, WhatIfResult)> = (0..node_count)
        .filter(|&i| !closed_set[i])
        .map(|i| (i, what_if_close(graph, i, closed_set)))
        .filter(|(_, r)| r.transitive_unblocks > 0)
        .collect();

    results.sort_by(|a, b| b.1.transitive_unblocks.cmp(&a.1.transitive_unblocks));
    results.truncate(n);
    results
}
```

