```

## Rust Implementation (articulation.rs)
```rust
use crate::graph::DiGraph;

/// Find articulation points using Tarjan's algorithm.
/// Works on undirected view of the graph.
pub fn articulation_points(graph: &DiGraph) -> Vec<usize> {
    let n = graph.node_count();
    if n == 0 {
        return Vec::new();
    }

    // Build undirected adjacency
    let neighbors = build_undirected(graph);

    let mut disc = vec![0usize; n];
    let mut low = vec![0usize; n];
    let mut parent = vec![usize::MAX; n];
    let mut ap = vec![false; n];
    let mut visited = vec![false; n];
    let mut time = 0usize;

    fn dfs(
        v: usize,
        neighbors: &[Vec<usize>],
        disc: &mut [usize],
        low: &mut [usize],
        parent: &mut [usize],
        ap: &mut [bool],
        visited: &mut [bool],
        time: &mut usize,
    ) {
        visited[v] = true;
        *time += 1;
        disc[v] = *time;
        low[v] = *time;
        let mut children = 0;

        for &u in &neighbors[v] {
            if !visited[u] {
                children += 1;
                parent[u] = v;
                dfs(u, neighbors, disc, low, parent, ap, visited, time);
                low[v] = low[v].min(low[u]);

                // v is root with >1 child, or non-root with low[u] >= disc[v]
                if parent[v] == usize::MAX && children > 1 {
                    ap[v] = true;
                }
                if parent[v] != usize::MAX && low[u] >= disc[v] {
                    ap[v] = true;
                }
            } else if u != parent[v] {
                low[v] = low[v].min(disc[u]);
            }
        }
    }

    for v in 0..n {
        if !visited[v] {
            dfs(v, &neighbors, &mut disc, &mut low, &mut parent, &mut ap, &mut visited, &mut time);
        }
    }

    ap.iter().enumerate()
        .filter(|(_, &is_ap)| is_ap)
        .map(|(i, _)| i)
        .collect()
}

fn build_undirected(graph: &DiGraph) -> Vec<Vec<usize>> {
    let n = graph.node_count();
    let mut neighbors: Vec<Vec<usize>> = vec![Vec::new(); n];

    for u in 0..n {
        for &v in graph.successors(u) {
            if !neighbors[u].contains(&v) { neighbors[u].push(v); }
            if !neighbors[v].contains(&u) { neighbors[v].push(u); }
        }
    }

    neighbors
}
```

