# Port Betweenness Centrality to Rust WASM

## Context
Betweenness centrality measures how often a node lies on shortest paths between other nodes. High betweenness = bottleneck that many paths flow through. We need both exact (Brandes) and approximate (sampling) versions.

## Go Implementation Reference
```go
// Exact: network.Betweenness(a.g) - O(V*E)
// Approximate: ApproxBetweenness(a.g, sampleSize) - O(k*E)
```

## Rust Implementation

### betweenness.rs
```rust
use crate::graph::DiGraph;
use std::collections::VecDeque;

/// Compute exact betweenness centrality using Brandes' algorithm.
/// Complexity: O(V*E) for unweighted graphs.
pub fn betweenness(graph: &DiGraph) -> Vec<f64> {
    let n = graph.node_count();
    if n == 0 {
        return Vec::new();
    }

    let mut bc = vec![0.0; n];

    // Run single-source betweenness from each node
    for s in 0..n {
        single_source_betweenness(graph, s, &mut bc);
    }

    // Normalize (for undirected would divide by 2)
    bc
}

/// Compute approximate betweenness using k pivot samples.
/// Error: O(1/sqrt(k)) - with k=100, ~10% error in ranking.
pub fn betweenness_approx(graph: &DiGraph, sample_size: usize) -> Vec<f64> {
    let n = graph.node_count();
    if n == 0 {
        return Vec::new();
    }

    // For small graphs, use exact algorithm
    if sample_size >= n {
        return betweenness(graph);
    }

    let mut bc = vec![0.0; n];

    // Sample k random pivot nodes
    let pivots = sample_nodes(n, sample_size);

    for &pivot in &pivots {
        single_source_betweenness(graph, pivot, &mut bc);
    }

    // Scale up: BC_approx = BC_partial * (n / k)
    let scale = n as f64 / sample_size as f64;
    for score in &mut bc {
        *score *= scale;
    }

    bc
}

/// Single-source betweenness contribution (Brandes' algorithm).
fn single_source_betweenness(graph: &DiGraph, source: usize, bc: &mut [f64]) {
    let n = graph.node_count();

    // BFS data structures
    let mut stack: Vec<usize> = Vec::with_capacity(n);
    let mut pred: Vec<Vec<usize>> = vec![Vec::new(); n];
    let mut sigma = vec![0.0; n];  // Number of shortest paths
    let mut dist = vec![-1i32; n]; // Distance from source
    let mut delta = vec![0.0; n];  // Dependency accumulator

    // BFS from source
    sigma[source] = 1.0;
    dist[source] = 0;
    let mut queue = VecDeque::new();
    queue.push_back(source);

    while let Some(v) = queue.pop_front() {
        stack.push(v);

        for &w in graph.successors(v) {
            // First visit to w?
            if dist[w] < 0 {
                dist[w] = dist[v] + 1;
                queue.push_back(w);
            }

            // Is v on a shortest path to w?
            if dist[w] == dist[v] + 1 {
                sigma[w] += sigma[v];
                pred[w].push(v);
            }
        }
    }

    // Back-propagation of dependencies
    while let Some(w) = stack.pop() {
        for &v in &pred[w] {
            let coeff = sigma[v] / sigma[w] * (1.0 + delta[w]);
            delta[v] += coeff;
        }

        if w != source {
            bc[w] += delta[w];
        }
    }
}

/// Sample k unique indices from 0..n using Fisher-Yates.
fn sample_nodes(n: usize, k: usize) -> Vec<usize> {
    use std::time::{SystemTime, UNIX_EPOCH};

    let seed = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|d| d.as_nanos() as u64)
        .unwrap_or(42);

    let mut indices: Vec<usize> = (0..n).collect();
    let mut rng_state = seed;

    // Simple LCG for deterministic-ish sampling
    let lcg = |state: &mut u64| -> usize {
        *state = state.wrapping_mul(6364136223846793005).wrapping_add(1);
        (*state >> 33) as usize
    };

    for i in 0..k.min(n) {
        let j = i + lcg(&mut rng_state) % (n - i);
        indices.swap(i, j);
    }

    indices.truncate(k);
    indices
}

/// Recommend sample size based on graph size.
pub fn recommend_sample_size(node_count: usize) -> usize {
    match node_count {
        0..=99 => node_count,      // Small: exact
        100..=499 => 50.max(node_count / 5), // Medium: 20%
        500..=1999 => 100,         // Large: fixed
        _ => 200,                  // XL: larger fixed
    }
}

