# Port PageRank Algorithm to Rust WASM

## Context
PageRank is a centrality measure that identifies important nodes based on the structure of incoming links. In bv, high PageRank issues are central bottlenecks that many other issues depend on (directly or indirectly).

## Go Implementation Reference
```go
// From gonum: network.PageRank(a.g, 0.85, 1e-6)
// Damping factor: 0.85 (standard)
// Tolerance: 1e-6 (convergence threshold)
```

## Rust Implementation

### pagerank.rs
```rust
use crate::graph::DiGraph;

/// PageRank configuration
pub struct PageRankConfig {
    /// Damping factor (typically 0.85)
    pub damping: f64,
    /// Convergence tolerance
    pub tolerance: f64,
    /// Maximum iterations
    pub max_iterations: u32,
}

impl Default for PageRankConfig {
    fn default() -> Self {
        PageRankConfig {
            damping: 0.85,
            tolerance: 1e-6,
            max_iterations: 100,
        }
    }
}

/// Compute PageRank scores for all nodes.
/// 
/// Algorithm: Power iteration method
/// PR(v) = (1-d)/n + d * ОЈ PR(u)/out_degree(u) for all u вҶ’ v
///
/// Returns vector of scores in node index order.
pub fn pagerank(graph: &DiGraph, config: &PageRankConfig) -> Vec<f64> {
    let n = graph.node_count();
    if n == 0 {
        return Vec::new();
    }

    let d = config.damping;
    let base = (1.0 - d) / n as f64;

    // Initialize with uniform distribution
    let mut scores = vec![1.0 / n as f64; n];
    let mut new_scores = vec![0.0; n];

    // Pre-compute out-degrees
    let out_degrees: Vec<f64> = (0..n)
        .map(|i| graph.out_degree(i) as f64)
        .collect();

    for _ in 0..config.max_iterations {
        // Reset new scores
        for s in &mut new_scores {
            *s = base;
        }

        // Accumulate contributions from predecessors
        for v in 0..n {
            for &u in graph.predecessors(v) {
                if out_degrees[u] > 0.0 {
                    new_scores[v] += d * scores[u] / out_degrees[u];
                }
            }
        }

        // Handle dangling nodes (no outgoing edges)
        // Their rank "leaks" and is distributed uniformly
        let dangling_sum: f64 = (0..n)
            .filter(|&i| out_degrees[i] == 0.0)
            .map(|i| scores[i])
            .sum();
        let dangling_contrib = d * dangling_sum / n as f64;
        for s in &mut new_scores {
            *s += dangling_contrib;
        }

        // Check convergence
        let diff: f64 = scores.iter()
            .zip(new_scores.iter())
            .map(|(a, b)| (a - b).abs())
            .sum();

        std::mem::swap(&mut scores, &mut new_scores);

        if diff < config.tolerance {
            break;
        }
    }

    scores
}

#[cfg(test)]
