### OPFS Graceful Fallback
```javascript
async function cacheToOPFS(data) {
  // OPFS may not be available - that's okay
  if (!("storage" in navigator)) {
    console.info("OPFS not available, skipping cache");
    return false;
  }

  try {
    const root = await navigator.storage.getDirectory();
    const handle = await root.getFileHandle("beads.sqlite3", { create: true });
    const writable = await handle.createWritable();
    await writable.write(data);
    await writable.close();
    return true;
  } catch (e) {
    // Private browsing, permission denied, etc.
    console.info("OPFS cache unavailable:", e.message);
    return false;
  }
}
```

