### Database Loading
```javascript
const DB_STATE = {
  sql: null,          // sql.js library
  db: null,           // Database instance
  cacheKey: null,     // OPFS cache key
  source: 'network',  // 'network' | 'cache' | 'chunks'
};

async function loadDatabase() {
  // 1. Initialize sql.js
  DB_STATE.sql = await initSqlJs({
    locateFile: file => `./vendor/${file}`
  });

  // 2. Try OPFS cache first
  const cached = await loadFromOPFS();
  if (cached) {
    DB_STATE.db = new DB_STATE.sql.Database(cached);
    DB_STATE.source = 'cache';
    return;
  }

  // 3. Check for chunked database
  const config = await fetchJSON('./beads.sqlite3.config.json').catch(() => null);
  if (config?.chunked) {
    const chunks = await loadChunks(config);
    DB_STATE.db = new DB_STATE.sql.Database(chunks);
    DB_STATE.source = 'chunks';
  } else {
    // 4. Load single file
    const buf = await fetch('./beads.sqlite3').then(r => r.arrayBuffer());
    DB_STATE.db = new DB_STATE.sql.Database(new Uint8Array(buf));
    DB_STATE.source = 'network';
  }

  // 5. Cache to OPFS for next time
  await cacheToOPFS(DB_STATE.db.export());
}
```

### OPFS Caching (like mcp_agent_mail)
```javascript
async function loadFromOPFS() {
  if (!('storage' in navigator)) return null;
  try {
    const root = await navigator.storage.getDirectory();
    const handle = await root.getFileHandle('beads.sqlite3', { create: false });
    const file = await handle.getFile();
    return new Uint8Array(await file.arrayBuffer());
  } catch {
    return null;
  }
}

async function cacheToOPFS(data) {
  if (!('storage' in navigator)) return;
  try {
    const root = await navigator.storage.getDirectory();
    const handle = await root.getFileHandle('beads.sqlite3', { create: true });
    const writable = await handle.createWritable();
    await writable.write(data);
    await writable.close();
  } catch (e) {
    console.warn('OPFS cache failed:', e);
  }
}
```

### Query Layer
```javascript
function queryIssues(filters, sort, limit = 100, offset = 0) {
  let sql = `SELECT * FROM issue_overview_mv WHERE 1=1`;
  const params = [];

  if (filters.status?.length) {
    sql += ` AND status IN (${filters.status.map(() => '?').join(',')})`;
    params.push(...filters.status);
  }

  if (filters.search) {
    sql += ` AND id IN (SELECT id FROM issues_fts WHERE issues_fts MATCH ?)`;
    params.push(filters.search + '*'); // Prefix search
  }

  if (filters.labels?.length) {
    sql += ` AND (${filters.labels.map(() => `labels LIKE ?`).join(' OR ')})`;
    params.push(...filters.labels.map(l => `%"${l}"%`));
  }

  // Sorting
  const sortMap = {
    'priority': 'priority ASC, triage_score DESC',
    'updated': 'updated_at DESC',
    'score': 'triage_score DESC',
    'blocks': 'blocks_count DESC'
  };
  sql += ` ORDER BY ${sortMap[sort] || sortMap.priority}`;
  sql += ` LIMIT ? OFFSET ?`;
  params.push(limit, offset);

  return DB_STATE.db.exec(sql, params);
}

function searchIssues(term) {
  // FTS5 search with ranking
  return DB_STATE.db.exec(`
    SELECT id, title, snippet(issues_fts, 2, '<mark>', '</mark>', '...', 32) as snippet,
           bm25(issues_fts) as rank
    FROM issues_fts
    WHERE issues_fts MATCH ?
    ORDER BY rank
    LIMIT 50
  `, [term + '*']);
}

function getIssueDependencies(id) {
  const blocks = DB_STATE.db.exec(`
    SELECT i.* FROM issues i
    JOIN dependencies d ON i.id = d.depends_on_id
    WHERE d.issue_id = ? AND d.type = 'blocks'
  `, [id]);

  const blockedBy = DB_STATE.db.exec(`
    SELECT i.* FROM issues i
    JOIN dependencies d ON i.id = d.issue_id
    WHERE d.depends_on_id = ? AND d.type = 'blocks'
  `, [id]);

  return { blocks, blockedBy };
}
```

### Chunk Loading
```javascript
async function loadChunks(config) {
  const chunks = [];
  for (let i = 0; i < config.chunk_count; i++) {
    const chunkPath = `./chunks/${String(i).padStart(5, '0')}.bin`;
    const buf = await fetch(chunkPath).then(r => r.arrayBuffer());
    chunks.push(new Uint8Array(buf));
  }
  // Concatenate chunks
  const total = chunks.reduce((sum, c) => sum + c.length, 0);
  const combined = new Uint8Array(total);
  let offset = 0;
  for (const chunk of chunks) {
    combined.set(chunk, offset);
    offset += chunk.length;
  }
  return combined;
}
```

