# Implement SQLite Export Pipeline

## Context
Export bv's issue data to a SQLite database optimized for client-side querying with sql.js WASM. This follows mcp_agent_mail's proven architecture.

## Requirements

### Main Export Function
```go
// pkg/export/sqlite_export.go

type SQLiteExporter struct {
    issues    []*model.Issue
    graph     *analysis.Graph
    insights  *analysis.InsightsOutput
    triage    *analysis.TriageOutput
    plan      *analysis.PlanOutput
    config    ExportConfig
}

func (e *SQLiteExporter) Export(outputDir string) error {
    // 1. Create SQLite database
    db, err := sql.Open("sqlite3", filepath.Join(outputDir, "beads.sqlite3"))

    // 2. Create schema
    if err := e.createSchema(db); err != nil { return err }

    // 3. Populate issues
    if err := e.insertIssues(db); err != nil { return err }

    // 4. Populate dependencies
    if err := e.insertDependencies(db); err != nil { return err }

    // 5. Compute and insert metrics
    if err := e.insertMetrics(db); err != nil { return err }

    // 6. Create FTS5 index
    if err := e.createFTSIndex(db); err != nil { return err }

    // 7. Create materialized views
    if err := e.createMaterializedViews(db); err != nil { return err }

    // 8. Optimize for httpvfs
    if err := e.optimizeDatabase(db); err != nil { return err }

    // 9. Write robot outputs as JSON (for full detail)
    if err := e.writeRobotOutputs(outputDir); err != nil { return err }

    // 10. Chunk if large
    if err := e.chunkIfNeeded(outputDir); err != nil { return err }

    return nil
}
```

### Database Optimization (Critical for Performance)
```go
func (e *SQLiteExporter) optimizeDatabase(db *sql.DB) error {
    optimizations := []string{
        "PRAGMA journal_mode=DELETE",      // Single file
        "PRAGMA page_size=1024",           // Optimal for httpvfs
        "INSERT INTO issues_fts(issues_fts) VALUES('optimize')",
        "ANALYZE",
        "PRAGMA optimize",
        "VACUUM",
    }
    for _, sql := range optimizations {
        if _, err := db.Exec(sql); err != nil {
            return fmt.Errorf("optimization %q failed: %w", sql, err)
        }
    }
    return nil
}
```

### Chunking for Large Databases (>5MB)
```go
func (e *SQLiteExporter) chunkIfNeeded(outputDir string) error {
    dbPath := filepath.Join(outputDir, "beads.sqlite3")
    info, _ := os.Stat(dbPath)

    if info.Size() < 5*1024*1024 { // <5MB, no chunking needed
        return nil
    }

    // Split into 1MB chunks for efficient range requests
    chunkSize := 1 * 1024 * 1024
    return e.splitIntoChunks(dbPath, outputDir, chunkSize)
}
```

### Metrics Insertion
```go
func (e *SQLiteExporter) insertMetrics(db *sql.DB) error {
    stmt, _ := db.Prepare(`
        INSERT INTO issue_metrics 
        (issue_id, pagerank, betweenness, critical_path_depth, triage_score, blocks_count, blocked_by_count)
        VALUES (?, ?, ?, ?, ?, ?, ?)
    `)
    defer stmt.Close()

    for _, issue := range e.issues {
        id := issue.ID
        pr := e.insights.FullStats.PageRank[id]
        bw := e.insights.FullStats.Betweenness[id]
        depth := e.getPathDepth(id)
        score := e.getTriageScore(id)
        blocks := len(e.graph.GetBlockedBy(id))
        blockedBy := len(e.graph.GetBlocks(id))

        stmt.Exec(id, pr, bw, depth, score, blocks, blockedBy)
    }
    return nil
}
```

### FTS5 Population
```go
func (e *SQLiteExporter) createFTSIndex(db *sql.DB) error {
    // Create FTS5 table
    _, err := db.Exec(`
        CREATE VIRTUAL TABLE issues_fts USING fts5(
            id, title, description, labels, assignee,
            content='issues', content_rowid='rowid',
            tokenize='porter unicode61'
        )
    `)
    if err != nil { return err }

    // Populate from issues table
    _, err = db.Exec(`
        INSERT INTO issues_fts(issues_fts) VALUES('rebuild')
    `)
    return err
}
