### Rust Crate (pkg/export/wasm_scorer/src/lib.rs)

```rust
use wasm_bindgen::prelude::*;
use serde::{Deserialize, Serialize};

#[derive(Serialize, Deserialize)]
pub struct Weights {
    pub text: f64,
    pub pagerank: f64,
    pub status: f64,
    pub impact: f64,
    pub priority: f64,
    pub recency: f64,
}

#[derive(Serialize, Deserialize)]
pub struct IssueMetrics {
    pub id: String,
    pub text_score: f64,
    pub pagerank: f64,
    pub status: u8,      // 0=open, 1=in_progress, 2=blocked, 3=closed
    pub priority: u8,    // 0-4
    pub blocker_count: u32,
    pub days_since_update: f64,
}

#[derive(Serialize, Deserialize)]
pub struct ScoredResult {
    pub id: String,
    pub score: f64,
    pub text_score: f64,
    pub components: [f64; 5], // pagerank, status, impact, priority, recency
}

#[wasm_bindgen]
pub struct HybridScorer {
    weights: Weights,
    max_blocker_count: u32,
}

#[wasm_bindgen]
impl HybridScorer {
    #[wasm_bindgen(constructor)]
    pub fn new(weights_json: &str) -> HybridScorer {
        let weights: Weights = serde_json::from_str(weights_json).unwrap();
        HybridScorer { weights, max_blocker_count: 1 }
    }

    /// Score a batch of issues and return sorted results
    /// Input: JSON array of IssueMetrics
    /// Output: JSON array of ScoredResult, sorted by score DESC
    #[wasm_bindgen]
    pub fn score_batch(&mut self, metrics_json: &str) -> String {
        let metrics: Vec<IssueMetrics> = serde_json::from_str(metrics_json).unwrap();

        // Update max blocker count
        self.max_blocker_count = metrics.iter()
            .map(|m| m.blocker_count)
            .max()
            .unwrap_or(1)
            .max(1);

        let mut results: Vec<ScoredResult> = metrics.iter()
            .map(|m| self.score_single(m))
            .collect();

        // Sort by score descending
        results.sort_by(|a, b| b.score.partial_cmp(&a.score).unwrap());

        serde_json::to_string(&results).unwrap()
    }

    fn score_single(&self, m: &IssueMetrics) -> ScoredResult {
        let status_score = Self::normalize_status(m.status);
        let priority_score = Self::normalize_priority(m.priority);
        let impact_score = m.blocker_count as f64 / self.max_blocker_count as f64;
        let recency_score = (-m.days_since_update / 30.0).exp();

        let score = 
            self.weights.text * m.text_score +
            self.weights.pagerank * m.pagerank +
            self.weights.status * status_score +
            self.weights.impact * impact_score +
            self.weights.priority * priority_score +
            self.weights.recency * recency_score;

        ScoredResult {
            id: m.id.clone(),
            score,
            text_score: m.text_score,
            components: [m.pagerank, status_score, impact_score, priority_score, recency_score],
        }
    }

    fn normalize_status(status: u8) -> f64 {
        match status {
            0 => 1.0,   // open
            1 => 0.8,   // in_progress
            2 => 0.5,   // blocked
            3 => 0.1,   // closed
            _ => 0.5,
        }
    }

    fn normalize_priority(priority: u8) -> f64 {
        match priority {
            0 => 1.0, 1 => 0.8, 2 => 0.6, 3 => 0.4, 4 => 0.2, _ => 0.5
        }
    }
}
